    [t(4),t(2),t(4),t(2),t(8),t(2),t(4),t(8)],
    [t(4),t(2),t(4),t(4),t(2),t(8),t(2),t(4)],  // swap col 1,2: [4,4,2,4,...] nope
    [t(8),t(4),t(2),t(8),t(4),t(2),t(8),t(4)],
    [t(2),t(8),t(4),t(2),t(8),t(4),t(2),t(8)],
    [t(4),t(2),t(8),t(4),t(2),t(8),t(4),t(2)],
    [t(8),t(4),t(2),t(8),t(4),t(2),t(8),t(4)],
    [t(2),t(8),t(4),t(2),t(8),t(4),t(2),t(8)],
];

// Better: place three 2s in positions (0,0),(0,1),(0,3), swap (0,2)<->(0,3) wait that breaks it.
// Simpler: row 0: 4,4,2,4 — swap (0,2)<->(0,3): becomes 4,4,4,2 → 3-match!
const boardSimple = [
    [t(4),t(4),t(2),t(4),t(8),t(2),t(4),t(8)],
    [t(2),t(4),t(8),t(2),t(4),t(8),t(2),t(4)],
    [t(4),t(2),t(8),t(4),t(2),t(8),t(4),t(2)],
    [t(8),t(4),t(2),t(8),t(4),t(2),t(8),t(4)],
    [t(2),t(8),t(4),t(2),t(8),t(4),t(2),t(8)],
    [t(4),t(2),t(8),t(4),t(2),t(8),t(4),t(2)],
    [t(8),t(4),t(2),t(8),t(4),t(2),t(8),t(4)],
    [t(2),t(8),t(4),t(2),t(8),t(4),t(2),t(8)],
];

const game = {
    board: boardSimple,
    boardWidth: 8,
    boardHeight: 8,
    tileValues: [2, 4, 8, 16, 32],
    spawnableTileValues: [2, 4],
    specialTileConfig: {},
    movesUsed: 0,
    maxMoves: 10,
    initialBlockedTileCount: 0,
    cursedTileCreatedCount: {},
    levelGoals: [
        { goalType: "score", target: 10, current: 0 },  // any non-zero score wins
    ],
};

console.time("solver");
const result = findSolutionPath(game, { maxDepth: 10, beamWidth: 3 });
console.timeEnd("solver");
console.log("Result:", JSON.stringify({
    solvable: result.solvable,
    moves: result.moves,
    path: result.path,
    seed: result.seed,
}, null, 2));

// Verify by simulating the path and checking goals at the end.
if (result.solvable && result.path.length > 0) {
    let goals = game.levelGoals.map(g => ({...g}));
    let boardState = game.board;
    const rng = mulberry32(result.seed);
    for (const swap of result.path) {
        const simGame = { ...game, board: boardState, levelGoals: goals };
        const r = simulateMove(simGame, swap, { rng, levelGoals: goals, initialBlockedTileCount: 0 });
        console.log(`  swap ${JSON.stringify(swap)} valid=${r.valid} scoreDelta=${r.scoreDelta} satisfied=${r.allGoalsSatisfied}`);
        boardState = r.newBoard;
        goals = r.levelGoals;
    }
    console.log("Final satisfied:", areGoalsSatisfied(goals));
}
