  // Walk DOM to find game instance via event listeners won't work. Let's find it via DOMContentLoaded closure variables.
  // Game code attaches handlers to buttons — get game from there.
  // Alternative: dispatch keydown "n" to advance levels, but first I need to monkey-patch.
  // Quick fix: override window.game by re-instantiating? No, that'd break state.
  // Easiest: grep for a globally accessible reference. Several callback handlers reference `this` — the game.
  // Try: buttons may have a closure. Let me attach via DOM mutation:
  const btn = document.getElementById("restartBtn");
  if (!btn) return { error: "no restartBtn" };
  // Just report what buttons are visible.
  const visible = [];
  document.querySelectorAll("button").forEach(b => {
    if (b.offsetParent !== null) visible.push({ id: b.id, text: b.textContent?.trim().slice(0, 30) });
  });
  return { title: document.title, visible };
}

