async () => {
  // Force-load all relevant modules, capture the Match3Game class + a game instance.
  const gameMod = await import("/src/game.js");
  const solverMod = await import("/src/solver.js");
  const simMod = await import("/src/simulation.js");
  const hintMod = await import("/src/hint-system.js");
  window.Match3Game = gameMod.Match3Game;
  window.solverMod = solverMod;
  window.simMod = simMod;
  window.hintMod = hintMod;

  // Reuse the already-created game by patching Match3Game.prototype to save itself on construction.
  // Since one was already constructed in DOMContentLoaded, try to find it via document elements' event handlers:
  // easier: instantiate a new one just to test solver behavior headlessly.
  return {
    classes: { Match3Game: typeof gameMod.Match3Game, findSolutionPath: typeof solverMod.findSolutionPath },
  };
}

async () => {
  // Create a fresh game, load level 1, populate the board, then force showExtraMovesDialog.
  const game = new window.Match3Game();

  // Wait for any init to settle
  await new Promise(r => setTimeout(r, 100));

  game.loadLevel(1);
  game.createBoard();

  const result = {
    level: game.currentLevel,
    goals: game.levelGoals.map(g => ({ type: g.goalType, target: g.target, tileValue: g.tileValue })),
    movesUsed: game.movesUsed,
    maxMoves: game.maxMoves,
    boardSize: `${game.boardWidth}x${game.boardHeight}`,
  };

  // Run solver directly on the loaded game
  const t0 = performance.now();
  const solverResult = window.solverMod.findSolutionPath(game, { maxDepth: 10, beamWidth: 3 });
  const elapsed = performance.now() - t0;

  return {
    ...result,
    solver: { solvable: solverResult.solvable, moves: solverResult.moves, seed: solverResult.seed, elapsed: Math.round(elapsed) + "ms" },
  };
}

async () => {
  // Create a fresh game, load a harder level, show extra moves dialog, check the hint text.
  const game = new window.Match3Game();
  await new Promise(r => setTimeout(r, 100));
  game.loadLevel(5); // medium difficulty
  game.createBoard();
  game.renderBoard();
  game.setupExtraMovesDialog();

  // Set state to simulate PoS condition: moves used up
  game.movesUsed = game.maxMoves;

